import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"mParticle iOS","description":"","frontmatter":{"title":"mParticle iOS","slug":"mparticle-ios"},"headers":[],"relativePath":"developer-hub/mparticle-ios.md","filePath":"developer-hub/mparticle-ios.md"}'),r={name:"developer-hub/mparticle-ios.md"};function o(l,e,s,c,h,p){return t(),i("div",null,[...e[0]||(e[0]=[n(`<p>This documentation explains how to send <strong>mParticle events to your Branch dashboard</strong>. If you&#39;d like to send Branch installs to your mParticle dashboard, please review the <a href="./mparticle-export.html">Branch/mParticle Data Integration</a>.</p><div class="info custom-block"><p class="custom-block-title">These instructions apply to the mParticle SDK version 7+ integration</p><p>mParticle introduced a new attribution &amp; deep linking API in v7 of their SDK (<a href="http://docs.mparticle.com/developers/sdk/ios/getting-started/#upgrade-to-version-7-of-the-sdk" target="_blank" rel="noreferrer">http://docs.mparticle.com/developers/sdk/ios/getting-started/#upgrade-to-version-7-of-the-sdk</a>), so please contact your Branch or mParticle Account Managers for more details, if you have mParticle SDK &lt; v7 installed in your app.</p></div><div class="warning custom-block"><p class="custom-block-title">Inconsistent Universal links behavior on iOS 11.2</p><p>After updating a device to iOS 11.2, we found that the app&#39;s AASA file is no longer downloaded reliably onto your user&#39;s device after an app install. As a result, clicking on Universal links will no longer open the app consistenly. You can set <a href="./creating-a-deep-link.html#redirections">forced uri redirect mode</a> on your Branch Links to open the app with URI schemes.</p></div><h2 id="technical-requirements" tabindex="-1">Technical Requirements <a class="header-anchor" href="#technical-requirements" aria-label="Permalink to &quot;Technical Requirements&quot;">​</a></h2><ul><li><a href="https://docs.mparticle.com/developers/sdk/ios/getting-started/" target="_blank" rel="noreferrer">mParticle SDK for iOS</a></li><li><a href="https://github.com/mparticle-integrations/mparticle-apple-integration-branchmetrics" target="_blank" rel="noreferrer">mParticle Branch Kit</a></li></ul><div class="info custom-block"><p class="custom-block-title">iOS 14 Implementation</p><p>In order to give you full control over the user experience, the Branch SDK will not trigger the IDFA permission modal.</p><p>However, we will still collect and use IDFAs when available if you do choose to trigger the modal.</p><p><a href="./ios-14-faqs.html">LEARN MORE</a></p></div><h2 id="branch-setup" tabindex="-1">Branch Setup <a class="header-anchor" href="#branch-setup" aria-label="Permalink to &quot;Branch Setup&quot;">​</a></h2><h3 id="configure-bundle-identifier" tabindex="-1">Configure bundle identifier <a class="header-anchor" href="#configure-bundle-identifier" aria-label="Permalink to &quot;Configure bundle identifier&quot;">​</a></h3><ul><li><p>Make sure Bundle Id matches your Branch configuration:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab, then find the <strong>Mobile Routing</strong> section and select <strong>iOS</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/settings/link" target="_blank" rel="noreferrer">Link Settings page</a>.</li></ul></li></ul><h3 id="confirm-app-prefix" tabindex="-1">Confirm App Prefix <a class="header-anchor" href="#confirm-app-prefix" aria-label="Permalink to &quot;Confirm App Prefix&quot;">​</a></h3><ul><li>From your <a href="https://developer.apple.com/account/ios/identifier/bundle" target="_blank" rel="noreferrer">Apple Developer Account</a></li></ul><h3 id="configure-branch-enable-universal-links" tabindex="-1">Configure Branch &amp; Enable Universal Links <a class="header-anchor" href="#configure-branch-enable-universal-links" aria-label="Permalink to &quot;Configure Branch &amp; Enable Universal Links&quot;">​</a></h3><ul><li><p>Enter a URI scheme and <a href="./ios-universal-links.html#section-enable-universal-links-on-the-branch-dashboard">enable Universal Links</a>:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab, then find the <strong>Mobile Routing</strong> section and select <strong>iOS</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/settings/link" target="_blank" rel="noreferrer">Link Settings page</a>.</li></ul></li></ul><h3 id="configure-associated-domains" tabindex="-1">Configure Associated Domains <a class="header-anchor" href="#configure-associated-domains" aria-label="Permalink to &quot;Configure Associated Domains&quot;">​</a></h3><ul><li><p>Add your link domains from Branch:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Find your link domains in the <strong>Link Routing Rules</strong> tab.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/settings/link" target="_blank" rel="noreferrer">Link Settings page</a>.</li></ul></li><li><p><code>-alternate</code> is needed for Universal Linking with the <a href="./web-sdk-overview.html">Web SDK</a> inside your Website</p></li><li><p><code>test-</code> is needed if you need use a test key</p></li><li><p>If you use a <a href="https://help.branch.io/#change-link-domain" target="_blank" rel="noreferrer">custom link domain</a>, you will need to include your old link domain, your <code>-alternate</code> link domain, and your new link domain</p></li></ul><h3 id="configure-entitlements" tabindex="-1">Configure Entitlements <a class="header-anchor" href="#configure-entitlements" aria-label="Permalink to &quot;Configure Entitlements&quot;">​</a></h3><ul><li>Confirm entitlements are within target</li></ul><h3 id="configure-info-plist" tabindex="-1">Configure <code>info.pList</code> <a class="header-anchor" href="#configure-info-plist" aria-label="Permalink to &quot;Configure \`info.pList\`&quot;">​</a></h3><ul><li><p>Add Branch values:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Keys &amp; Domains</strong> to find your Branch key and link domain.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/account-settings/app" target="_blank" rel="noreferrer">Account Settings page</a>.</li><li>Add <code>branch_app_domain</code> with your live key domain</li><li>Add your URI scheme as <code>URL Types</code> -&gt; <code>Item 0</code> -&gt; <code>URL Schemes</code></li><li>Do NOT add your API keys to the file (mParticle handles this via the dashboard)</li></ul></li></ul><h2 id="mparticle-setup" tabindex="-1">mParticle Setup <a class="header-anchor" href="#mparticle-setup" aria-label="Permalink to &quot;mParticle Setup&quot;">​</a></h2><h3 id="enable-branch-on-mparticle" tabindex="-1">Enable Branch on mParticle <a class="header-anchor" href="#enable-branch-on-mparticle" aria-label="Permalink to &quot;Enable Branch on mParticle&quot;">​</a></h3><ul><li><p>Before you can enable Branch in your mParticle dashboard, you must retrieve your Branch Key:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Keys &amp; Domains</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/settings/link" target="_blank" rel="noreferrer">Link Settings</a> page.</li></ul></li><li><p>Please follow mParticle&#39;s documentation on how to <a href="https://docs.mparticle.com/guides/getting-started/connect-an-event-output/" target="_blank" rel="noreferrer">Connect an Event Output</a>; i.e. enable the Branch integration.</p></li><li><p>If you have enabled Apple Ads for your Branch implementation, you must also check <code>Enable Apple Ads</code> in the Connection Settings.</p></li></ul><p>Once you have added the kit and configured your branch API key in the mParticle dashboard, the mParticle SDKs will take care of initializing the Branch SDK and forwarding the appropriate application lifecycle events to handle deep links.</p><h3 id="install-the-mparticle-branch-kit" tabindex="-1">Install the mParticle Branch Kit <a class="header-anchor" href="#install-the-mparticle-branch-kit" aria-label="Permalink to &quot;Install the mParticle Branch Kit&quot;">​</a></h3><h4 id="option-1-cocoapods" tabindex="-1">Option 1: <a href="https://cocoapods.org/" target="_blank" rel="noreferrer">CocoaPods</a> <a class="header-anchor" href="#option-1-cocoapods" aria-label="Permalink to &quot;Option 1: [CocoaPods](https://cocoapods.org/)&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>platform :ios, &#39;8.0&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        target &#39;APP_NAME&#39; do</span></span>
<span class="line"><span>        # if swift</span></span>
<span class="line"><span>        use_frameworks!</span></span>
<span class="line"><span></span></span>
<span class="line"><span>        &#39;pod &#39;mParticle-BranchMetrics&#39;, &#39;~&gt; 8&#39;</span></span>
<span class="line"><span>        end</span></span></code></pre></div><h4 id="option-2-carthage" tabindex="-1">Option 2: <a href="https://github.com/Carthage/Carthage" target="_blank" rel="noreferrer">Carthage</a> <a class="header-anchor" href="#option-2-carthage" aria-label="Permalink to &quot;Option 2: [Carthage](https://github.com/Carthage/Carthage)&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>github &quot;mparticle-integrations/mparticle-apple-integration-branchmetrics&quot;</span></span></code></pre></div><h3 id="import-ios-support-libraries" tabindex="-1">Import iOS Support Libraries <a class="header-anchor" href="#import-ios-support-libraries" aria-label="Permalink to &quot;Import iOS Support Libraries&quot;">​</a></h3><ul><li><code>AdSupport</code></li><li><code>SafariServices</code></li><li><code>MobileCoreServices</code></li><li><code>CoreSpotlight</code></li><li><code>iAd</code></li></ul><h3 id="initializing-branch-in-the-mparticle-kit" tabindex="-1">Initializing Branch in the mParticle Kit <a class="header-anchor" href="#initializing-branch-in-the-mparticle-kit" aria-label="Permalink to &quot;Initializing Branch in the mParticle Kit&quot;">​</a></h3><p>The mParticle iOS SDK (version 5.4.1 and later) will automatically call the following methods of the Branch Kit:</p><ul><li><code>initSessionWithLaunchOptions:</code> within <code>application:didFinishLaunchingWithOptions:</code></li><li><code>handleDeepLink:</code> within <code>application:openURL:options:</code></li><li><code>continueUserActivity:</code> within <code>application:continueUserActivity:restorationHandler:</code></li></ul><p>This means mParticle will automatically handle initializing Branch sessions. However, please ensure <code>.onAttributionComplete</code> is enabled in the <code>mParticleOptions</code> object.</p><div class="warning custom-block"><p class="custom-block-title">mParticle appDelegate proxy not enabled</p><p>If the mParticle appDelegate proxy is not enabled, you must add mParticle&#39;s <a href="https://docs.mparticle.com/developers/sdk/ios/configuration/#uiapplication-delegate-proxy" target="_blank" rel="noreferrer">URI &amp; Domain relays</a> to the appDelegate.</p></div><p>At this point you should start seeing your Branch session data - including installs, re-opens, and any custom events - in your Branch dashboard.</p><h3 id="retrieve-deep-link-data-via-mparticle" tabindex="-1">Retrieve Deep Link Data via mParticle <a class="header-anchor" href="#retrieve-deep-link-data-via-mparticle" aria-label="Permalink to &quot;Retrieve Deep Link Data via mParticle&quot;">​</a></h3><p>Our integration with mParticle supports the creation and attribution of deep links to install and open an app. A deep link will typically contain some additional information to be used when the user ultimately opens your application, so that you can properly route the user to the appropriate content, or otherwise customize their experience.</p><p>Please ensure you&#39;ve followed <a href="http://docs.mparticle.com/developers/sdk/ios/kits#deep-linking" target="_blank" rel="noreferrer">mParticle&#39;s documentation</a> to ensure your deep link data is being retrieved.</p><div class="info custom-block"><p class="custom-block-title">mParticle in React Native</p><p>If you integrate mParticle in React Native, you will still integrate the Branch kit as a Native module and follow the setup steps above. However, instead of retrieving deep link data in the the native layer, you&#39;ll retrieve deep link data via <a href="https://github.com/mParticle/react-native-mparticle/blob/master/README.md#attribution" target="_blank" rel="noreferrer">mParticle&#39;s React Native function found here</a>.</p></div><h4 id="nativelinktm-deferred-deep-linking" tabindex="-1">NativeLink™ Deferred Deep Linking <a class="header-anchor" href="#nativelinktm-deferred-deep-linking" aria-label="Permalink to &quot;NativeLink™ Deferred Deep Linking&quot;">​</a></h4><ul><li>Use iOS pasteboard to enable deferred deep linking via Branch NativeLink™</li></ul><div class="warning custom-block"><p class="custom-block-title">Prerequisite</p><p><strong>Make sure the underlying iOS SDK Version is v1.39.4+</strong></p><p>To use this feature you must:</p><ul><li><p><a href="./configure-default-link-behaviors.html#3-ios-default-link-behavior">Enable NativeLink™ Deep Linking</a>:</p><ul><li><strong>New Branch</strong>: In the left-hand navigation, go to <strong>Configuration</strong> and click on <strong>Link Controls</strong>. Navigate to the <strong>Link Routing Rules</strong> tab, then find the <strong>Mobile Routing</strong> section and select <strong>iOS</strong>.</li><li><strong>Legacy Branch</strong>: Navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration page</a>.</li></ul><p><strong>or</strong></p></li><li><p>Manually configure your Branch Link to use <a href="./creating-a-deep-link.html#deep-linking">$ios_nativelink</a></p></li></ul></div><p>Implement one of the <a href="./ios-advanced-features.html#options-for-implementation">pasteboard opt-in options</a> in the native iOS SDK code.</p><p>Please note that deferred deep linking is part of our Engagement package. Learn more on our pricing <a href="./packaging.html">page</a>.</p><h2 id="test-deep-link" tabindex="-1">Test Deep Link <a class="header-anchor" href="#test-deep-link" aria-label="Permalink to &quot;Test Deep Link&quot;">​</a></h2><ol><li>Create a deep link in <a href="https://dashboard.branch.io/marketing" target="_blank" rel="noreferrer">Branch</a>.</li><li>Delete your app from the device.</li><li>Compile and test on a device.</li><li>Paste deep link in <strong>Apple Notes.</strong></li><li>Long press on the deep link (not 3D Touch).</li><li>Click **Open in &quot;APP_NAME&quot;**to open your app.</li></ol><h2 id="implementing-features" tabindex="-1">Implementing Features <a class="header-anchor" href="#implementing-features" aria-label="Permalink to &quot;Implementing Features&quot;">​</a></h2><ul><li>Please refer to mParticle&#39;s <a href="https://docs.mparticle.com/developers/sdk/ios/kits/#making-direct-calls-to-kits" target="_blank" rel="noreferrer">making direct calls to kits</a> documentation for how to access the Branch kit via the mParticle SDK.</li><li>Once you have a reference to the Branch kit, refer to Branch&#39;s <a href="./ios-advanced-features.html#section-create-content-reference">native iOS SDK</a> documentation on how to implement secondary functionality.</li></ul><h2 id="sample-testing-apps" tabindex="-1">Sample Testing Apps <a class="header-anchor" href="#sample-testing-apps" aria-label="Permalink to &quot;Sample Testing Apps&quot;">​</a></h2><ul><li><a href="https://github.com/mparticle-integrations/mparticle-apple-integration-branchmetrics/tree/master/Examples" target="_blank" rel="noreferrer">Example Applications</a></li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>Please refer to the <a href="./ios-troubleshooting.html">Branch iOS SDK troubleshooting section</a>.</p>`,53)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
